import{_ as a,o as s,c as i,a3 as e}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"Kafka 简介","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/kafka/index.md","filePath":"middleware/kafka/index.md","lastUpdated":1780474278000}'),n={name:"middleware/kafka/index.md"};function r(d,t,o,l,h,p){return s(),i("div",null,[...t[0]||(t[0]=[e(`<h1 id="kafka-jian-jie" tabindex="-1">Kafka 简介 <a class="header-anchor" href="#kafka-jian-jie" aria-label="Permalink to &quot;Kafka 简介&quot;">​</a></h1><p>Apache Kafka 是一个开源的<strong>分布式事件流平台</strong>，由 LinkedIn 开发并捐赠给 Apache 基金会，使用 Java 和 Scala 编写。Kafka 以<strong>高吞吐、低延迟、持久化</strong>著称，广泛应用于消息队列、日志收集、流处理、事件溯源等场景。</p><h2 id="yu-xiao-xi-dui-lie-dui-bi" tabindex="-1">与消息队列对比 <a class="header-anchor" href="#yu-xiao-xi-dui-lie-dui-bi" aria-label="Permalink to &quot;与消息队列对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比</th><th>传统 MQ（RabbitMQ）</th><th>Kafka</th></tr></thead><tbody><tr><td>消息模型</td><td>消费后删除</td><td>持久化到磁盘，基于 Offset 消费</td></tr><tr><td>吞吐量</td><td>万级/秒</td><td>百万级/秒</td></tr><tr><td>延迟</td><td>微秒级</td><td>毫秒级</td></tr><tr><td>消费模式</td><td>Push（Broker 推）</td><td>Pull（Consumer 拉）</td></tr><tr><td>数据回溯</td><td>不支持</td><td>支持，可重复消费历史数据</td></tr><tr><td>顺序保证</td><td>全局无序</td><td>Partition 内有序</td></tr><tr><td>扩展方式</td><td>垂直扩展为主</td><td>水平扩展（Partition + Broker）</td></tr></tbody></table><h2 id="he-xin-te-xing" tabindex="-1">核心特性 <a class="header-anchor" href="#he-xin-te-xing" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><ul><li><strong>高吞吐</strong>：顺序写入磁盘 + Page Cache + 零拷贝（sendfile）实现百万级 QPS</li><li><strong>持久化</strong>：消息写入磁盘，默认保留 7 天，支持回溯消费</li><li><strong>水平扩展</strong>：通过增加 Broker 和 Partition 线性扩展吞吐</li><li><strong>高可用</strong>：副本机制（ISR），Broker 故障自动 Leader 切换</li><li><strong>Pull 模型</strong>：Consumer 按自身节奏拉取，避免 Push 导致的消费方过载</li></ul><h2 id="he-xin-gai-nian" tabindex="-1">核心概念 <a class="header-anchor" href="#he-xin-gai-nian" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="xiao-xi-mo-xing" tabindex="-1">消息模型 <a class="header-anchor" href="#xiao-xi-mo-xing" aria-label="Permalink to &quot;消息模型&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Producer-1 ──┐                    ┌── Consumer-1 (Group-A)</span></span>
<span class="line"><span>             ├── Topic &quot;orders&quot; ──┤</span></span>
<span class="line"><span>Producer-2 ──┘   Partition-0      ├── Consumer-2 (Group-A)</span></span>
<span class="line"><span>                 Partition-1      │</span></span>
<span class="line"><span>                 Partition-2      └── Consumer-3 (Group-B) ← 独立消费</span></span></code></pre></div><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td><strong>Producer</strong></td><td>生产者，向指定 Topic 发送消息，可指定 Partition 或自动分区</td></tr><tr><td><strong>Consumer</strong></td><td>消费者，从 Topic 拉取消息，属于某个 Consumer Group</td></tr><tr><td><strong>Broker</strong></td><td>Kafka 服务节点，一个集群包含多个 Broker</td></tr><tr><td><strong>Topic</strong></td><td>消息的逻辑分类，类似数据库的&quot;表&quot;</td></tr><tr><td><strong>Partition</strong></td><td>Topic 的物理分片，每个 Partition 是一个有序、不可变的消息序列</td></tr><tr><td><strong>Offset</strong></td><td>消息在 Partition 中的唯一递增编号，Consumer 用 Offset 标记消费位置</td></tr><tr><td><strong>Consumer Group</strong></td><td>消费者组，组内每个 Consumer 负责不同 Partition，实现负载均衡</td></tr></tbody></table><h3 id="xiao-xi-jie-gou" tabindex="-1">消息结构 <a class="header-anchor" href="#xiao-xi-jie-gou" aria-label="Permalink to &quot;消息结构&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>Key</td><td>可选，用于分区路由；相同 Key 的消息进入同一 Partition</td></tr><tr><td>Value</td><td>消息体，字节数组，支持任意序列化格式</td></tr><tr><td>Headers</td><td>可选，键值对元数据（用于链路追踪等）</td></tr><tr><td>Timestamp</td><td>消息时间戳（CreateTime / LogAppendTime）</td></tr></tbody></table><h3 id="ji-ben-cao-zuo" tabindex="-1">基本操作 <a class="header-anchor" href="#ji-ben-cao-zuo" aria-label="Permalink to &quot;基本操作&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建 Topic</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-topics.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --topic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --partitions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --replication-factor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看 Topic 列表</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-topics.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 生产消息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-console-producer.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --topic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 消费消息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-console-consumer.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --topic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --from-beginning</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span></span></code></pre></div><h2 id="kraft-mo-shitui-jian" tabindex="-1">KRaft 模式（推荐） <a class="header-anchor" href="#kraft-mo-shitui-jian" aria-label="Permalink to &quot;KRaft 模式（推荐）&quot;">​</a></h2><p>Kafka 2.8+ 引入了 <strong>KRaft</strong>（Kafka Raft）模式，用内置 Raft 协议取代 ZooKeeper 进行元数据管理，Kafka 3.3+ 生产可用，3.7+ 已弃用 ZooKeeper 模式。</p><table tabindex="0"><thead><tr><th>对比</th><th>ZooKeeper 模式</th><th>KRaft 模式</th></tr></thead><tbody><tr><td>外部依赖</td><td>需要 ZooKeeper 集群</td><td>无，自包含</td></tr><tr><td>运维复杂度</td><td>高，两套系统</td><td>低，仅 Kafka 自身</td></tr><tr><td>元数据恢复</td><td>依赖 ZK 快照</td><td>Kafka 内置 Raft 日志</td></tr><tr><td>Partition 上限</td><td>~200K/集群（ZK 瓶颈）</td><td>≥ 2M/集群</td></tr><tr><td>部署组件</td><td>Broker + Controller（ZK 选主）</td><td>Broker + Controller（Raft 选主）</td></tr></tbody></table><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/" target="_blank" rel="noreferrer">Apache Kafka Official Documentation</a></li><li><a href="https://kafka.apache.org/documentation/#kraft" target="_blank" rel="noreferrer">Kafka KRaft Mode</a></li></ul>`,19)])])}const g=a(n,[["render",r]]);export{c as __pageData,g as default};
